code_example:
# Dictionary
student = {
    'name': 'Bob',
    'age': 20,
    'grades': [85, 90, 92]
}

print(student['name'])
print(student.get('email', 'N/A'))  # Safe access

# Dictionary methods
for key, value in student.items():
    print(f'{key}: {value}')

# Sets
nums1 = {1, 2, 3, 4}
nums2 = {3, 4, 5, 6}

print(nums1 | nums2)  # Union: {1,2,3,4,5,6}
print(nums1 & nums2)  # Intersection: {3,4}
print(nums1 - nums2)  # Difference: {1,2}

# Remove duplicates
items = [1, 2, 2, 3, 3, 3]
unique_items = list(set(items))
print(unique_items)
